1	package handlers
2	
3	import (
4		"fmt"
5		"strconv"
6	
7		"github.com/gofiber/fiber/v2"
8	
9		"w2t86/internal/middleware"
10		"w2t86/internal/observability"
11		"w2t86/internal/repository"
12		"w2t86/internal/services"
13	)
14	
15	// OrderHandler handles all order-lifecycle HTTP routes for both student and
16	// admin/clerk users.
17	type OrderHandler struct {
18		orderService *services.OrderService
19	}
20	
21	// NewOrderHandler creates an OrderHandler backed by the given service.
22	func NewOrderHandler(os *services.OrderService) *OrderHandler {
23		return &OrderHandler{orderService: os}
24	}
25	
26	// ---------------------------------------------------------------
27	// Student routes
28	// ---------------------------------------------------------------
29	
30	// ListOrders handles GET /orders — renders the authenticated user's order list.
31	func (h *OrderHandler) ListOrders(c *fiber.Ctx) error {
32		user := middleware.GetUser(c)
33	
34		limit := 20
35		offset := 0
36		if p := c.QueryInt("page", 1); p > 1 {
37			offset = (p - 1) * limit
38		}
39	
40		orders, err := h.orderService.GetOrdersForUser(user.ID, limit, offset)
41		if err != nil {
42			return internalErr(c, observability.Orders, "get orders for user failed", err, "user_id", user.ID)
43		}
44	
45		return c.Render("orders/list", fiber.Map{
46			"Title":      "My Orders",
47			"User":       user,
48			"Orders":     orders,
49			"ActivePage": "orders",
50		}, "layouts/base")
51	}
52	
53	// OrderDetail handles GET /orders/:id — renders the full order detail page.
54	func (h *OrderHandler) OrderDetail(c *fiber.Ctx) error {
55		id, err := c.ParamsInt("id")
56		if err != nil {
57			return apiErr(c, fiber.StatusBadRequest, "Invalid order ID")
58		}
59	
60		user := middleware.GetUser(c)
61	
62		order, items, err := h.orderService.GetOrderByID(int64(id))
63		if err != nil {
64			return apiErr(c, fiber.StatusNotFound, "Order not found")
65		}
66	
67		// Students may only view their own orders.
68		if user.Role == "student" && order.UserID != user.ID {
69			observability.Security.Warn("unauthorized order access attempt",
70				"user_id", user.ID, "order_id", id, "order_owner_id", order.UserID, "ip", c.IP())
71			return apiErr(c, fiber.StatusForbidden, "You do not have permission to perform this action")
72		}
73	
74		events, err := h.orderService.GetOrderEvents(int64(id))
75		if err != nil {
76			observability.Orders.Warn("get order events failed", "order_id", id, "error", err)
77			events = nil
78		}
79	
80		// Enrich items with backorder status — an item is backordered when
81		// fulfillment_status is "backordered".
82		return c.Render("orders/detail", fiber.Map{
83			"Title":      fmt.Sprintf("Order #%d", id),
84			"User":       user,
85			"Order":      order,
86			"Items":      items,
87			"Events":     events,
88			"ActivePage": "orders",
89		}, "layouts/base")
90	}
91	
92	// CartPage handles GET /orders/cart — renders the cart/checkout page.
93	// Items are expected as query parameters: material_id[]=1&qty[]=2 etc.
94	func (h *OrderHandler) CartPage(c *fiber.Ctx) error {
95		user := middleware.GetUser(c)
96		return c.Render("orders/cart", fiber.Map{
97			"Title":      "Checkout",
98			"User":       user,
99			"ActivePage": "orders",
100		}, "layouts/base")
101	}
102	
103	// PlaceOrder handles POST /orders — places an order from the submitted cart form.
104	func (h *OrderHandler) PlaceOrder(c *fiber.Ctx) error {
105		user := middleware.GetUser(c)
106	
107		// Parse multi-value form fields: material_id[] and qty[] and unit_price[].
108		materialIDs := c.Request().PostArgs().PeekMulti("material_id")
109		qtys := c.Request().PostArgs().PeekMulti("qty")
110		prices := c.Request().PostArgs().PeekMulti("unit_price")
111	
112		if len(materialIDs) == 0 || len(materialIDs) != len(qtys) {
113			return htmxErr(c, fiber.StatusBadRequest, "Invalid cart data")
114		}
115	
116		items := make([]repository.OrderItemInput, 0, len(materialIDs))
117		for i, rawID := range materialIDs {
118			mid, err := strconv.ParseInt(string(rawID), 10, 64)
119			if err != nil {
120				return htmxErr(c, fiber.StatusBadRequest, "Invalid material ID in cart")
121			}
122			qty, err := strconv.Atoi(string(qtys[i]))
123			if err != nil || qty <= 0 {
124				return htmxErr(c, fiber.StatusBadRequest, "Invalid quantity in cart")
125			}
126			var unitPrice float64
127			if i < len(prices) {
128				unitPrice, _ = strconv.ParseFloat(string(prices[i]), 64)
129			}
130			items = append(items, repository.OrderItemInput{
131				MaterialID: mid,
132				Qty:        qty,
133				UnitPrice:  unitPrice,
134			})
135		}
136	
137		order, err := h.orderService.PlaceOrder(user.ID, items)
138		if err != nil {
139			observability.Orders.Warn("place order rejected", "user_id", user.ID, "error", err)
140			errData := fiber.Map{
141				"Title": "Checkout",
142				"User":  user,
143				"Error": "Could not place your order. Please check your cart and try again.",
144			}
145			if c.Get("HX-Request") == "true" {
146				return c.Status(fiber.StatusUnprocessableEntity).Render("orders/cart", errData)
147			}
148			return c.Status(fiber.StatusUnprocessableEntity).Render("orders/cart", errData, "layouts/base")
149		}
150	
151		observability.Orders.Info("order placed by user", "order_id", order.ID, "user_id", user.ID)
152		return c.Redirect(fmt.Sprintf("/orders/%d", order.ID), fiber.StatusFound)
153	}
154	
155	// ConfirmPayment handles POST /orders/:id/pay — confirms payment via HTMX.
156	func (h *OrderHandler) ConfirmPayment(c *fiber.Ctx) error {
157		id, err := c.ParamsInt("id")
158		if err != nil {
159			return apiErr(c, fiber.StatusBadRequest, "Invalid order ID")
160		}
161	
162		user := middleware.GetUser(c)
163		if err := h.orderService.ConfirmPayment(int64(id), user.ID); err != nil {
164			return htmxErr(c, fiber.StatusUnprocessableEntity, "Could not confirm payment. Please try again.")
165		}
166	
167		if c.Get("HX-Request") == "true" {
168			// Return updated status badge partial.
169			return c.Render("partials/order_status_badge", fiber.Map{
170				"Status": "pending_shipment",
171			})
172		}
173		return c.Redirect(fmt.Sprintf("/orders/%d", id), fiber.StatusFound)
174	}
175	
176	// CancelOrder handles POST /orders/:id/cancel — cancels an order.
177	func (h *OrderHandler) CancelOrder(c *fiber.Ctx) error {
178		id, err := c.ParamsInt("id")
179		if err != nil {
180			return apiErr(c, fiber.StatusBadRequest, "Invalid order ID")
181		}
182	
183		user := middleware.GetUser(c)
184		if err := h.orderService.CancelOrder(int64(id), user.ID, user.Role); err != nil {
185			return htmxErr(c, fiber.StatusUnprocessableEntity, "Could not cancel order. Please try again.")
186		}
187	
188		if c.Get("HX-Request") == "true" {
189			return c.Render("partials/order_status_badge", fiber.Map{
190				"Status": "canceled",
191			})
192		}
193		return c.Redirect(fmt.Sprintf("/orders/%d", id), fiber.StatusFound)
194	}
195	
196	// ---------------------------------------------------------------
197	// Clerk / Admin routes
198	// ---------------------------------------------------------------
199	
200	// AdminListOrders handles GET /admin/orders — all orders with optional filters.
201	func (h *OrderHandler) AdminListOrders(c *fiber.Ctx) error {
202		user := middleware.GetUser(c)
203	
204		status := c.Query("status")
205		dateFrom := c.Query("date_from")
206		dateTo := c.Query("date_to")
207	
208		limit := 50
209		offset := 0
210		if p := c.QueryInt("page", 1); p > 1 {
211			offset = (p - 1) * limit
212		}
213	
214		orders, err := h.orderService.GetAllOrders(status, dateFrom, dateTo, limit, offset)
215		if err != nil {
216			return internalErr(c, observability.Orders, "get all orders failed", err, "status", status)
217		}
218	
219		return c.Render("admin/orders/list", fiber.Map{
220			"Title":        "All Orders",
221			"User":         user,
222			"Orders":       orders,
223			"StatusFilter": status,
224			"DateFrom":     dateFrom,
225			"DateTo":       dateTo,
226			"ActivePage":   "orders",
227		}, "layouts/base")
228	}
229	
230	// MarkShipped handles POST /admin/orders/:id/ship.
231	func (h *OrderHandler) MarkShipped(c *fiber.Ctx) error {
232		id, err := c.ParamsInt("id")
233		if err != nil {
234			return apiErr(c, fiber.StatusBadRequest, "Invalid order ID")
235		}
236	
237		user := middleware.GetUser(c)
238		if err := h.orderService.MarkShipped(int64(id), user.ID); err != nil {
239			return htmxErr(c, fiber.StatusUnprocessableEntity, "Could not mark order as shipped. Please try again.")
240		}
241	
242		if c.Get("HX-Request") == "true" {
243			return c.Render("partials/order_status_badge", fiber.Map{
244				"Status": "in_transit",
245			})
246		}
247		return c.Redirect(fmt.Sprintf("/admin/orders/%d", id), fiber.StatusFound)
248	}
249	
250	// MarkDelivered handles POST /admin/orders/:id/deliver.
251	func (h *OrderHandler) MarkDelivered(c *fiber.Ctx) error {
252		id, err := c.ParamsInt("id")
253		if err != nil {
254			return apiErr(c, fiber.StatusBadRequest, "Invalid order ID")
255		}
256	
257		user := middleware.GetUser(c)
258		if err := h.orderService.MarkDelivered(int64(id), user.ID); err != nil {
259			return htmxErr(c, fiber.StatusUnprocessableEntity, "Could not mark order as delivered. Please try again.")
260		}
261	
262		if c.Get("HX-Request") == "true" {
263			return c.Render("partials/order_status_badge", fiber.Map{
264				"Status": "completed",
265			})
266		}
267		return c.Redirect(fmt.Sprintf("/admin/orders/%d", id), fiber.StatusFound)
268	}
269	
270	// ---------------------------------------------------------------
271	// Returns routes
272	// ---------------------------------------------------------------
273	
274	// SubmitReturnRequest handles POST /orders/:id/returns.
275	func (h *OrderHandler) SubmitReturnRequest(c *fiber.Ctx) error {
276		id, err := c.ParamsInt("id")
277		if err != nil {
278			return apiErr(c, fiber.StatusBadRequest, "Invalid order ID")
279		}
280	
281		user := middleware.GetUser(c)
282		reqType := c.FormValue("type")
283		reason := c.FormValue("reason")
284	
285		rr, err := h.orderService.RequestReturn(int64(id), user.ID, reqType, reason)
286		if err != nil {
287			observability.Orders.Warn("return request rejected", "order_id", id, "user_id", user.ID, "type", reqType, "error", err)
288			return htmxErr(c, fiber.StatusUnprocessableEntity, "Could not submit return request. Please check your input and try again.")
289		}
290	
291		observability.Orders.Info("return request submitted", "request_id", rr.ID, "order_id", id, "user_id", user.ID, "type", reqType)
292	
293		if c.Get("HX-Request") == "true" {
294			return c.Render("partials/flash", fiber.Map{
295				"Message": fmt.Sprintf("Return request #%d submitted.", rr.ID),
296			})
297		}
298		return c.Redirect("/returns", fiber.StatusFound)
299	}
300	
301	// ListReturnRequests handles GET /returns — user's own return requests.
302	func (h *OrderHandler) ListReturnRequests(c *fiber.Ctx) error {
303		user := middleware.GetUser(c)
304	
305		requests, err := h.orderService.GetReturnRequestsForUser(user.ID)
306		if err != nil {
307			observability.Orders.Warn("get return requests for user failed", "user_id", user.ID, "error", err)
308			requests = nil
309		}
310	
311		return c.Render("returns/list", fiber.Map{
312			"Title":    "My Returns",
313			"User":     user,
314			"Requests": requests,
315		}, "layouts/base")
316	}
317	
318	// AdminListReturnRequests handles GET /admin/returns — pending returns queue.
319	func (h *OrderHandler) AdminListReturnRequests(c *fiber.Ctx) error {
320		user := middleware.GetUser(c)
321	
322		limit := 50
323		offset := 0
324		if p := c.QueryInt("page", 1); p > 1 {
325			offset = (p - 1) * limit
326		}
327	
328		requests, err := h.orderService.GetPendingReturnRequests(limit, offset)
329		if err != nil {
330			observability.Orders.Warn("get pending return requests failed", "error", err)
331			requests = nil
332		}
333	
334		return c.Render("admin/returns/list", fiber.Map{
335			"Title":    "Return Requests",
336			"User":     user,
337			"Requests": requests,
338		}, "layouts/base")
339	}
340	
341	// ApproveReturn handles POST /admin/returns/:id/approve.
342	func (h *OrderHandler) ApproveReturn(c *fiber.Ctx) error {
343		id, err := c.ParamsInt("id")
344		if err != nil {
345			return apiErr(c, fiber.StatusBadRequest, "Invalid return request ID")
346		}
347	
348		user := middleware.GetUser(c)
349		if err := h.orderService.ApproveReturn(int64(id), user.ID, user.Role); err != nil {
350			return htmxErr(c, fiber.StatusUnprocessableEntity, "Could not approve return request. Please try again.")
351		}
352	
353		observability.Orders.Info("return request approved", "request_id", id, "actor_id", user.ID, "role", user.Role)
354	
355		if c.Get("HX-Request") == "true" {
356			return c.Render("partials/flash", fiber.Map{
357				"Message": fmt.Sprintf("Return request #%d approved.", id),
358			})
359		}
360		return c.Redirect("/admin/returns", fiber.StatusFound)
361	}
362	
363	// RejectReturn handles POST /admin/returns/:id/reject.
364	func (h *OrderHandler) RejectReturn(c *fiber.Ctx) error {
365		id, err := c.ParamsInt("id")
366		if err != nil {
367			return apiErr(c, fiber.StatusBadRequest, "Invalid return request ID")
368		}
369	
370		user := middleware.GetUser(c)
371		if err := h.orderService.RejectReturn(int64(id), user.ID); err != nil {
372			return htmxErr(c, fiber.StatusUnprocessableEntity, "Could not reject return request. Please try again.")
373		}
374	
375		observability.Orders.Info("return request rejected", "request_id", id, "actor_id", user.ID)
376	
377		if c.Get("HX-Request") == "true" {
378			return c.Render("partials/flash", fiber.Map{
379				"Message": fmt.Sprintf("Return request #%d rejected.", id),
380			})
381		}
382		return c.Redirect("/admin/returns", fiber.StatusFound)
383	}
