70	// ConfirmPayment transitions an order from pending_payment → pending_shipment.
71	// Only the order owner may confirm payment.
72	func (s *OrderService) ConfirmPayment(orderID, userID int64) error {
73		order, err := s.orderRepo.GetByID(orderID)
74		if err != nil {
75			return fmt.Errorf("service: ConfirmPayment: %w", err)
76		}
77		if order.UserID != userID {
78			return errors.New("service: ConfirmPayment: not authorized")
79		}
80		if order.Status != "pending_payment" {
81			return fmt.Errorf("service: ConfirmPayment: order is %q, expected pending_payment", order.Status)
82		}
83		if err := s.orderRepo.Transition(orderID, userID, "pending_shipment", "payment confirmed", s.materialRepo); err != nil {
84			return err
85		}
86		observability.Orders.Info("payment confirmed", "order_id", orderID, "user_id", userID)
87		return nil
88	}
89	
90	// CancelOrder cancels an order. Business rules:
91	//   - Students can only cancel their own orders when in pending_payment.
92	//   - Clerks cannot cancel orders.
93	//   - Admins/instructors can cancel pending_payment or pending_shipment orders.
94	//   - Only admins can cancel in_transit orders.
95	func (s *OrderService) CancelOrder(orderID, actorID int64, role string) error {
96		order, err := s.orderRepo.GetByID(orderID)
97		if err != nil {
98			return fmt.Errorf("service: CancelOrder: %w", err)
99		}
100	
101		switch role {
102		case "student":
103			if order.UserID != actorID {
104				return errors.New("service: CancelOrder: not authorized")
105			}
106			if order.Status != "pending_payment" {
107				return fmt.Errorf("service: CancelOrder: students may only cancel orders in pending_payment (current: %q)", order.Status)
108			}
109		case "admin", "instructor":
110			if order.Status == "in_transit" && role != "admin" {
111				return errors.New("service: CancelOrder: only admins can cancel in-transit orders")
112			}
113			if order.Status == "completed" {
114				return errors.New("service: CancelOrder: completed orders cannot be canceled")
115			}
116			if order.Status == "canceled" {
117				return errors.New("service: CancelOrder: order is already canceled")
118			}
119		case "clerk":
120			return errors.New("service: CancelOrder: clerks are not permitted to cancel orders")
121		default:
122			return errors.New("service: CancelOrder: unknown role")
123		}
124	
125		note := fmt.Sprintf("canceled by %s (id=%d)", role, actorID)
126		if err := s.orderRepo.Transition(orderID, actorID, "canceled", note, s.materialRepo); err != nil {
127			return err
128		}
129		observability.Orders.Info("order canceled", "order_id", orderID, "actor_id", actorID, "role", role, "reason", "user_requested")
130		observability.M.OrdersCanceled.Add(1)
131		return nil
132	}
133	
134	// ---------------------------------------------------------------
135	// Clerk actions
136	// ---------------------------------------------------------------
137	
138	// MarkShipped transitions an order from pending_shipment → in_transit.
139	// Only clerks (or admins) may call this.
140	func (s *OrderService) MarkShipped(orderID, actorID int64) error {
141		order, err := s.orderRepo.GetByID(orderID)
142		if err != nil {
143			return fmt.Errorf("service: MarkShipped: %w", err)
144		}
145		if order.Status != "pending_shipment" {
146			return fmt.Errorf("service: MarkShipped: order is %q, expected pending_shipment", order.Status)
147		}
148		return s.orderRepo.Transition(orderID, actorID, "in_transit", "order shipped", s.materialRepo)
149	}
150	
151	// MarkDelivered transitions an order from in_transit → completed.
152	// Only clerks (or admins) may call this.
153	func (s *OrderService) MarkDelivered(orderID, actorID int64) error {
154		order, err := s.orderRepo.GetByID(orderID)
155		if err != nil {
156			return fmt.Errorf("service: MarkDelivered: %w", err)
157		}
158		if order.Status != "in_transit" {
159			return fmt.Errorf("service: MarkDelivered: order is %q, expected in_transit", order.Status)
160		}
161		return s.orderRepo.Transition(orderID, actorID, "completed", "order delivered", s.materialRepo)
162	}
163	
164	// ---------------------------------------------------------------
165	// Returns / Exchanges / Refunds
166	// ---------------------------------------------------------------
167	
168	// RequestReturn submits a return/exchange/refund request for an order.
169	// Rules:
170	//   - The order must belong to the requesting user.
171	//   - Return/exchange: allowed only within 14 days of order completion.
172	//   - Refund: also allowed only within 14 days; requires manager role enforcement
173	//     at the handler layer (admin or instructor).
174	//   - Only one pending request may be open per order at a time.
175	func (s *OrderService) RequestReturn(orderID, userID int64, reqType, reason string) (*models.ReturnRequest, error) {
176		order, err := s.orderRepo.GetByID(orderID)
177		if err != nil {
178			return nil, fmt.Errorf("service: RequestReturn: %w", err)
179		}
180		if order.UserID != userID {
181			return nil, errors.New("service: RequestReturn: not authorized")
182		}
183		if order.Status != "completed" {
184			return nil, errors.New("service: RequestReturn: returns are only allowed on completed orders")
185		}
186	
187		switch reqType {
188		case "return", "exchange", "refund":
189			// valid types
190		default:
191			return nil, fmt.Errorf("service: RequestReturn: invalid type %q (must be return, exchange, or refund)", reqType)
192		}
193	
194		// Enforce 14-day window.
195		if !repository.WithinReturnWindow(order.UpdatedAt) {
196			return nil, errors.New("service: RequestReturn: the 14-day return window has expired")
197		}
198	
199		// Check for an already-pending request on this order.
200		existing, err := s.orderRepo.GetReturnRequestsByUser(userID)
201		if err != nil {
202			return nil, fmt.Errorf("service: RequestReturn: check existing: %w", err)
203		}
204		for _, rr := range existing {
205			if rr.OrderID == orderID && rr.Status == "pending" {
206				return nil, errors.New("service: RequestReturn: a pending return request already exists for this order")
207			}
208		}
209	
210		rr, err := s.orderRepo.CreateReturnRequest(orderID, userID, reqType, reason)
211		if err != nil {
212			return nil, fmt.Errorf("service: RequestReturn: %w", err)
213		}
214		observability.Orders.Info("return requested", "order_id", orderID, "type", reqType)
215		return rr, nil
216	}
217	
218	// ApproveReturn approves a return request.
219	// Only admins and instructors (managers) may approve.
220	// When the request type is "refund" or "return", a financial_transaction record
221	// is created for traceability.
222	func (s *OrderService) ApproveReturn(requestID, actorID int64, role string) error {
223		if role != "admin" && role != "instructor" {
224			return errors.New("service: ApproveReturn: only managers (admin/instructor) may approve return requests")
225		}
226		rr, err := s.orderRepo.GetReturnRequestByID(requestID)
227		if err != nil {
228			return fmt.Errorf("service: ApproveReturn: %w", err)
229		}
230		if rr.Status != "pending" {
231			return fmt.Errorf("service: ApproveReturn: request is already %q", rr.Status)
232		}
233		if err := s.orderRepo.ResolveReturn(requestID, actorID, true); err != nil {
234			return err
235		}
236	
237		// Record a financial transaction for refund or return types.
238		if rr.Type == "refund" || rr.Type == "return" {
239			// Look up the order amount for the refund value.
240			amount := 0.0
241			if order, oErr := s.orderRepo.GetByID(rr.OrderID); oErr == nil {
242				amount = order.TotalAmount
243			}
244			txType := "refund"
245			note := "approved " + rr.Type + " request"
246			rrID := requestID
247			oID := rr.OrderID
248			if _, ftErr := s.orderRepo.CreateFinancialTransaction(
249				&oID, &rrID, txType, amount, actorID, note,
250			); ftErr != nil {
251				// Non-fatal: log but do not fail the approval.
252				observability.Orders.Warn("financial transaction record failed", "request_id", requestID, "error", ftErr)
253			}
254		}
255	
256		observability.Orders.Info("return approved", "request_id", requestID, "actor_id", actorID, "role", role, "type", rr.Type)
257		return nil
258	}
259	
260	// RejectReturn rejects a return request.
261	// Clerks, admins, and instructors may reject.
262	func (s *OrderService) RejectReturn(requestID, actorID int64) error {
263		rr, err := s.orderRepo.GetReturnRequestByID(requestID)
264		if err != nil {
265			return fmt.Errorf("service: RejectReturn: %w", err)
266		}
267		if rr.Status != "pending" {
268			return fmt.Errorf("service: RejectReturn: request is already %q", rr.Status)
269		}
270		if err := s.orderRepo.ResolveReturn(requestID, actorID, false); err != nil {
271			return err
272		}
273		observability.Orders.Info("return rejected", "request_id", requestID, "actor_id", actorID)
274		return nil
275	}
276	
