278	// Read-through helpers exposed to handlers
279	// ---------------------------------------------------------------
280	
281	// GetOrderByID returns the order and its items.
282	func (s *OrderService) GetOrderByID(orderID int64) (*models.Order, []models.OrderItem, error) {
283		order, err := s.orderRepo.GetByID(orderID)
284		if err != nil {
285			return nil, nil, fmt.Errorf("service: GetOrderByID: %w", err)
286		}
287		items, err := s.orderRepo.GetItemsByOrderID(orderID)
288		if err != nil {
289			return nil, nil, fmt.Errorf("service: GetOrderByID: items: %w", err)
290		}
291		return order, items, nil
292	}
293	
294	// GetOrdersForUser returns paginated orders for a user.
295	func (s *OrderService) GetOrdersForUser(userID int64, limit, offset int) ([]models.Order, error) {
296		return s.orderRepo.GetByUserID(userID, limit, offset)
297	}
