38	// CreateUser registers a new user account.  fullName is the person's real
39	// name used for duplicate detection; pass an empty string to leave it unset.
40	func (s *AdminService) CreateUser(username, email, password, role, fullName string) (*models.User, error) {
41		authSvc := &AuthService{userRepo: s.userRepo}
42		user, err := authSvc.Register(username, email, password, role)
43		if err != nil {
44			return nil, fmt.Errorf("service: AdminService.CreateUser: %w", err)
45		}
46		if fullName != "" {
47			if err := s.userRepo.SetFullName(user.ID, fullName); err != nil {
48				// Non-fatal: user was created; log and continue.
49				observability.App.Warn("set full_name failed", "user_id", user.ID, "error", err)
50			} else {
51				user.FullName = &fullName
52			}
53		}
54		return user, nil
55	}
56	
57	// UpdateUserRole changes a user's role and writes an audit log entry.
58	func (s *AdminService) UpdateUserRole(userID int64, role string, actorID int64, actorIP string) error {
59		// Capture before state.
60		before, _ := s.userRepo.GetByID(userID)
61	
62		if err := s.adminRepo.UpdateUserRole(userID, role); err != nil {
63			return fmt.Errorf("service: AdminService.UpdateUserRole: %w", err)
64		}
65	
66		// Write audit log (best-effort).
67		after, _ := s.userRepo.GetByID(userID)
68		_ = s.adminRepo.WriteAuditLog(actorID, "update_role", "user", userID, before, after, actorIP)
69		observability.Security.Info("role changed", "target_user_id", userID, "new_role", role, "actor_id", actorID)
70		return nil
71	}
72	
73	// UnlockUser clears a user's account lockout.
74	func (s *AdminService) UnlockUser(userID int64, actorID int64) error {
75		if err := s.adminRepo.UnlockUser(userID); err != nil {
76			return fmt.Errorf("service: AdminService.UnlockUser: %w", err)
77		}
78		_ = s.adminRepo.WriteAuditLog(actorID, "unlock", "user", userID, nil, nil, "")
79		observability.Security.Info("account unlocked", "target_user_id", userID, "actor_id", actorID)
80		return nil
81	}
82	
83	// SetCustomField stores a custom field for a user.
84	// If encrypt is true the value is AES-256-GCM encrypted with encKey before
85	// being stored; encKey must be exactly 32 bytes.
86	func (s *AdminService) SetCustomField(userID int64, name, value string, encrypt bool, encKey []byte) error {
87		stored := value
88		if encrypt && len(encKey) == 32 {
89			enc, err := crypto.EncryptField(encKey, value)
90			if err != nil {
91				return fmt.Errorf("service: AdminService.SetCustomField: encrypt: %w", err)
92			}
93			stored = enc
94		}
95		return s.adminRepo.SetCustomField(userID, name, stored, encrypt)
96	}
97	
98	// GetCustomFields returns all custom fields for a user.
99	// Encrypted fields have their FieldValue replaced with the plaintext if encKey
100	// is provided and 32 bytes; otherwise the raw (ciphertext) value is returned.
101	func (s *AdminService) GetCustomFields(userID int64, encKey []byte) ([]models.UserCustomField, error) {
102		fields, err := s.adminRepo.GetCustomFields(userID)
103		if err != nil {
104			return nil, err
105		}
106		if len(encKey) == 32 {
107			for i, f := range fields {
108				if f.IsEncrypted == 1 && f.FieldValue != nil {
109					plain, decErr := crypto.DecryptField(encKey, *f.FieldValue)
110					if decErr == nil {
111						fields[i].FieldValue = &plain
112					}
113					// If decryption fails leave the raw value; caller can decide.
114				}
115			}
116		}
117		return fields, nil
118	}
119	
120	// DeleteCustomField removes a custom field for a user.
121	func (s *AdminService) DeleteCustomField(userID int64, name string) error {
122		return s.adminRepo.DeleteCustomField(userID, name)
123	}
