134	// MergeUsers merges duplicateID into primaryID and records the operation.
135	func (s *AdminService) MergeUsers(primaryID, duplicateID int64, actorID int64) error {
136		if err := s.adminRepo.MergeUsers(primaryID, duplicateID, actorID); err != nil {
137			return fmt.Errorf("service: AdminService.MergeUsers: %w", err)
138		}
139		_ = s.adminRepo.WriteAuditLog(actorID, "merge_user", "user", primaryID,
140			map[string]int64{"duplicate_id": duplicateID}, nil, "")
141		observability.Security.Warn("entities merged", "primary_id", primaryID, "duplicate_id", duplicateID, "actor_id", actorID)
142		return nil
143	}
