150	func (s *AdminService) GetAuditLog(entityType string, entityID int64, limit, offset int) ([]models.AuditLog, error) {
151		return s.adminRepo.GetAuditLog(entityType, entityID, limit, offset)
152	}
153	
154	// GetRecentAuditLog returns the most-recent limit audit log entries.
155	func (s *AdminService) GetRecentAuditLog(limit int) ([]models.AuditLog, error) {
156		return s.adminRepo.GetRecentAuditLog(limit)
157	}
