109	// markItemsFulfilled sets fulfillment_status='fulfilled' for each issued item
110	// and advances the order to in_transit if it was previously pending_shipment.
111	// Once all items are fulfilled the order moves to completed.
112	func (s *DistributionService) markItemsFulfilled(orderID, actorID int64, items []IssueItem) error {
113		for _, item := range items {
114			if err := s.orderRepo.MarkOrderItemFulfilled(orderID, item.MaterialID); err != nil {
115				return fmt.Errorf("markItemsFulfilled: update order_item: %w", err)
116			}
117		}
118	
119		// Advance order from pending_shipment → in_transit on first issue.
120		order, err := s.orderRepo.GetByID(orderID)
121		if err != nil {
122			return err
123		}
124		if order.Status == "pending_shipment" {
125			if err := s.orderRepo.Transition(orderID, actorID, "in_transit", "items issued by clerk", s.materialRepo); err != nil {
126				return fmt.Errorf("markItemsFulfilled: advance to in_transit: %w", err)
127			}
128		}
129	
130		return nil
131	}
