137	// RecordReturn records a "returned" distribution event and releases inventory
138	// (increments available_qty by qty).
139	func (s *DistributionService) RecordReturn(orderID, materialID, actorID int64, scanID string, qty int) error {
140		if qty <= 0 {
141			return errors.New("service: RecordReturn: qty must be positive")
142		}
143	
144		// Verify order exists.
145		if _, err := s.orderRepo.GetByID(orderID); err != nil {
146			if errors.Is(err, sql.ErrNoRows) {
147				return fmt.Errorf("service: RecordReturn: order %d not found", orderID)
148			}
149			return fmt.Errorf("service: RecordReturn: load order: %w", err)
150		}
151	
152		orderIDPtr := &orderID
153		actorIDPtr := &actorID
154		scanIDPtr := &scanID
155	
156		evt := &models.DistributionEvent{
157			OrderID:     orderIDPtr,
158			MaterialID:  materialID,
159			Qty:         qty,
160			EventType:   "returned",
161			ScanID:      scanIDPtr,
162			ActorID:     actorIDPtr,
163			CustodyFrom: stringPtr("student"),
164			CustodyTo:   stringPtr("clerk"),
165		}
166		if _, err := s.distRepo.RecordEvent(evt); err != nil {
167			return fmt.Errorf("service: RecordReturn: record event: %w", err)
168		}
169	
170		// Release inventory back to available stock.
171		if err := s.materialRepo.Release(materialID, qty); err != nil {
172			return fmt.Errorf("service: RecordReturn: release inventory: %w", err)
173		}
174	
175		observability.Distribution.Info("item returned", "order_id", orderID, "material_id", materialID, "qty", qty, "scan_id", scanID, "actor_id", actorID)
176		return nil
177	}
