179	// ---------------------------------------------------------------
180	// Exchange
181	// ---------------------------------------------------------------
182	
183	// RecordExchange swaps an old copy for a new one in a single logical operation:
184	//  1. Records a "returned" event for oldMaterialID.
185	//  2. Verifies the new material has available stock.
186	//  3. Records an "issued" event for newMaterialID and decrements its
187	//     available_qty.
188	func (s *DistributionService) RecordExchange(orderID, oldMaterialID, newMaterialID, actorID int64, scanID string, qty int) error {
189		if qty <= 0 {
190			return errors.New("service: RecordExchange: qty must be positive")
191		}
192	
193		// Return the old copy first (releases its inventory).
194		if err := s.RecordReturn(orderID, oldMaterialID, actorID, scanID, qty); err != nil {
195			return fmt.Errorf("service: RecordExchange: return old: %w", err)
196		}
197	
198		// Check new material stock.
199		newMat, err := s.materialRepo.GetByID(newMaterialID)
200		if err != nil {
201			if errors.Is(err, sql.ErrNoRows) {
202				return fmt.Errorf("service: RecordExchange: new material %d not found", newMaterialID)
203			}
204			return fmt.Errorf("service: RecordExchange: load new material: %w", err)
205		}
206		if newMat.AvailableQty < qty {
207			return fmt.Errorf("service: RecordExchange: insufficient stock for material %q (available %d, requested %d)",
208				newMat.Title, newMat.AvailableQty, qty)
209		}
210	
211		orderIDPtr := &orderID
212		actorIDPtr := &actorID
213		newScanID := scanID + "_exch"
214		scanIDPtr := &newScanID
215	
216		evt := &models.DistributionEvent{
217			OrderID:     orderIDPtr,
218			MaterialID:  newMaterialID,
219			Qty:         qty,
220			EventType:   "issued",
221			ScanID:      scanIDPtr,
222			ActorID:     actorIDPtr,
223			CustodyFrom: stringPtr("clerk"),
224			CustodyTo:   stringPtr("student"),
225		}
226		if _, err := s.distRepo.RecordEvent(evt); err != nil {
227			return fmt.Errorf("service: RecordExchange: record issue event: %w", err)
228		}
229	
230		// Reserve the newly issued material's inventory.
231		if err := s.materialRepo.Reserve(newMaterialID, qty); err != nil {
232			return fmt.Errorf("service: RecordExchange: reserve new material inventory: %w", err)
233		}
234	
235		observability.Distribution.Info("item exchanged", "order_id", orderID, "old_material_id", oldMaterialID, "new_material_id", newMaterialID, "qty", qty, "actor_id", actorID)
236		return nil
237	}
238	
239	
240	// ---------------------------------------------------------------
241	// Reissue
242	// ---------------------------------------------------------------
243	
244	// ReissueItem handles lost or damaged copy replacement:
245	//   - Records a "lost" or "damaged" event for oldScanID (marking it out of
246	//     circulation).
247	//   - Records a new "issued" event for newScanID.
248	//
249	// reason must be "lost" or "damaged".
250	func (s *DistributionService) ReissueItem(orderID, materialID, actorID int64, oldScanID, newScanID, reason string) error {
251		if reason != "lost" && reason != "damaged" {
252			return fmt.Errorf("service: ReissueItem: invalid reason %q (must be 'lost' or 'damaged')", reason)
253		}
254		if oldScanID == "" || newScanID == "" {
255			return errors.New("service: ReissueItem: both oldScanID and newScanID are required")
256		}
257	
258		// Verify order exists.
259		if _, err := s.orderRepo.GetByID(orderID); err != nil {
260			if errors.Is(err, sql.ErrNoRows) {
261				return fmt.Errorf("service: ReissueItem: order %d not found", orderID)
262			}
263			return fmt.Errorf("service: ReissueItem: load order: %w", err)
264		}
265	
266		orderIDPtr := &orderID
267		actorIDPtr := &actorID
268	
269		// Record the loss/damage event for the old scan ID.
270		oldEvt := &models.DistributionEvent{
271			OrderID:    orderIDPtr,
272			MaterialID: materialID,
273			Qty:        1,
274			EventType:  reason, // "lost" or "damaged"
275			ScanID:     &oldScanID,
276			ActorID:    actorIDPtr,
277		}
278		if _, err := s.distRepo.RecordEvent(oldEvt); err != nil {
279			return fmt.Errorf("service: ReissueItem: record %s event: %w", reason, err)
280		}
281	
282		// Issue the replacement copy.
283		newEvt := &models.DistributionEvent{
284			OrderID:     orderIDPtr,
285			MaterialID:  materialID,
286			Qty:         1,
287			EventType:   "issued",
288			ScanID:      &newScanID,
289			ActorID:     actorIDPtr,
290			CustodyFrom: stringPtr("clerk"),
291			CustodyTo:   stringPtr("student"),
292		}
293		if _, err := s.distRepo.RecordEvent(newEvt); err != nil {
294			return fmt.Errorf("service: ReissueItem: record replacement issue event: %w", err)
295		}
296	
297		observability.Distribution.Info("item reissued", "old_scan_id", oldScanID, "new_scan_id", newScanID, "reason", reason)
298		return nil
299	}
