244	// ReissueItem handles lost or damaged copy replacement:
245	//   - Records a "lost" or "damaged" event for oldScanID (marking it out of
246	//     circulation).
247	//   - Records a new "issued" event for newScanID.
248	//
249	// reason must be "lost" or "damaged".
250	func (s *DistributionService) ReissueItem(orderID, materialID, actorID int64, oldScanID, newScanID, reason string) error {
251		if reason != "lost" && reason != "damaged" {
252			return fmt.Errorf("service: ReissueItem: invalid reason %q (must be 'lost' or 'damaged')", reason)
253		}
254		if oldScanID == "" || newScanID == "" {
255			return errors.New("service: ReissueItem: both oldScanID and newScanID are required")
256		}
257	
258		// Verify order exists.
259		if _, err := s.orderRepo.GetByID(orderID); err != nil {
260			if errors.Is(err, sql.ErrNoRows) {
261				return fmt.Errorf("service: ReissueItem: order %d not found", orderID)
262			}
263			return fmt.Errorf("service: ReissueItem: load order: %w", err)
264		}
265	
266		orderIDPtr := &orderID
267		actorIDPtr := &actorID
268	
269		// Record the loss/damage event for the old scan ID.
270		oldEvt := &models.DistributionEvent{
271			OrderID:    orderIDPtr,
272			MaterialID: materialID,
273			Qty:        1,
274			EventType:  reason, // "lost" or "damaged"
275			ScanID:     &oldScanID,
276			ActorID:    actorIDPtr,
277		}
278		if _, err := s.distRepo.RecordEvent(oldEvt); err != nil {
279			return fmt.Errorf("service: ReissueItem: record %s event: %w", reason, err)
280		}
281	
282		// Issue the replacement copy.
283		newEvt := &models.DistributionEvent{
284			OrderID:     orderIDPtr,
285			MaterialID:  materialID,
286			Qty:         1,
287			EventType:   "issued",
288			ScanID:      &newScanID,
289			ActorID:     actorIDPtr,
290			CustodyFrom: stringPtr("clerk"),
291			CustodyTo:   stringPtr("student"),
292		}
293		if _, err := s.distRepo.RecordEvent(newEvt); err != nil {
294			return fmt.Errorf("service: ReissueItem: record replacement issue event: %w", err)
295		}
296	
297		observability.Distribution.Info("item reissued", "old_scan_id", oldScanID, "new_scan_id", newScanID, "reason", reason)
298		return nil
299	}
