260	// ExportOrdersCSV returns a CSV byte slice for orders, with UserName masked
261	// via crypto.MaskName and UserEmail masked via crypto.MaskID.
262	func (s *AnalyticsService) ExportOrdersCSV(status, dateFrom, dateTo string) ([]byte, error) {
263		rows, err := s.repo.ExportOrders(status, dateFrom, dateTo)
264		if err != nil {
265			return nil, fmt.Errorf("service: ExportOrdersCSV: %w", err)
266		}
267	
268		var buf bytes.Buffer
269		w := csv.NewWriter(&buf)
270	
271		// Header
272		if err := w.Write([]string{
273			"order_id", "user_name", "user_email", "status",
274			"total_amount", "created_at", "item_count",
275		}); err != nil {
276			return nil, fmt.Errorf("service: ExportOrdersCSV: write header: %w", err)
277		}
278	
279		for _, row := range rows {
280			record := []string{
281				strconv.FormatInt(row.OrderID, 10),
282				crypto.MaskName(row.UserName),
283				crypto.MaskID(row.UserEmail),
284				row.Status,
285				strconv.FormatFloat(row.TotalAmount, 'f', 2, 64),
286				row.CreatedAt,
287				strconv.Itoa(row.ItemCount),
288			}
289			if err := w.Write(record); err != nil {
290				return nil, fmt.Errorf("service: ExportOrdersCSV: write row: %w", err)
291			}
292		}
293	
294		w.Flush()
295		if err := w.Error(); err != nil {
296			return nil, fmt.Errorf("service: ExportOrdersCSV: flush: %w", err)
297		}
298		return buf.Bytes(), nil
299	}
