182	// geoJSONFeature is the internal representation of a GeoJSON Feature.
183	type geoJSONFeature struct {
184		Type     string                 `json:"type"`
185		Geometry geoJSONGeometry        `json:"geometry"`
186		Props    map[string]interface{} `json:"properties"`
187	}
188	
189	type geoJSONGeometry struct {
190		Type        string    `json:"type"`
191		Coordinates []float64 `json:"coordinates"`
192	}
193	
194	type geoJSONCollection struct {
195		Type     string           `json:"type"`
196		Features []geoJSONFeature `json:"features"`
197	}
198	
199	// locationsToGeoJSON converts a slice of Location rows into a GeoJSON
200	// FeatureCollection string.  Locations without lat/lng are skipped.
201	func locationsToGeoJSON(locations []models.Location) string {
202		features := make([]geoJSONFeature, 0, len(locations))
203		for _, loc := range locations {
204			if loc.Lat == nil || loc.Lng == nil {
205				continue
206			}
207			props := map[string]interface{}{
208				"id":   loc.ID,
209				"name": loc.Name,
210			}
211			if loc.Type != nil {
212				props["type"] = *loc.Type
213			}
214			if loc.Properties != nil {
215				// Attempt to merge the stored JSON properties blob.
216				var extra map[string]interface{}
217				if err := json.Unmarshal([]byte(*loc.Properties), &extra); err == nil {
218					for k, v := range extra {
219						props[k] = v
220					}
221				} else {
222					props["properties"] = *loc.Properties
223				}
224			}
225			features = append(features, geoJSONFeature{
226				Type: "Feature",
227				Geometry: geoJSONGeometry{
228					Type:        "Point",
229					Coordinates: []float64{*loc.Lng, *loc.Lat}, // GeoJSON order: [lng, lat]
230				},
231				Props: props,
232			})
233		}
234	
235		col := geoJSONCollection{
236			Type:     "FeatureCollection",
237			Features: features,
238		}
239		b, err := json.Marshal(col)
240		if err != nil {
241			return `{"type":"FeatureCollection","features":[]}`
242		}
243		return string(b)
244	}
