524		if status != "" {
525			q += " WHERE status = ?"
526			args = append(args, status)
527		}
528		q += " ORDER BY requested_at DESC LIMIT ? OFFSET ?"
529		args = append(args, limit, offset)
530	
531		rows, err := r.db.Query(q, args...)
