607	
608	// CloseOverdueOrders cancels all orders whose auto_close_at has passed and
609	// whose status is pending_payment or pending_shipment. Returns the count of
610	// orders closed.
611	func (r *OrderRepository) CloseOverdueOrders(materialRepo *MaterialRepository) (int, error) {
612		const selectQ = `
613			SELECT id, status
614			FROM   orders
615			WHERE  status IN ('pending_payment', 'pending_shipment')
616			  AND  auto_close_at IS NOT NULL
617			  AND  auto_close_at < datetime('now')`
618	
619		rows, err := r.db.Query(selectQ)
620		if err != nil {
621			return 0, fmt.Errorf("repository: CloseOverdueOrders: query: %w", err)
622		}
623		type row struct {
624			id     int64
625			status string
626		}
627		var overdue []row
628		for rows.Next() {
629			var rw row
630			if err := rows.Scan(&rw.id, &rw.status); err != nil {
631				rows.Close()
632				return 0, err
633			}
634			overdue = append(overdue, rw)
635		}
636		rows.Close()
637		if err := rows.Err(); err != nil {
638			return 0, err
639		}
640	
641		closed := 0
642		for _, rw := range overdue {
643			note := "auto-closed: payment timeout"
644			if rw.status == "pending_shipment" {
645				note = "auto-closed: shipment timeout"
646			}
647			if err := r.Transition(rw.id, 0, "canceled", note, materialRepo); err != nil {
648				// Log but continue — don't abort the whole batch on a single failure.
649				continue
650			}
651			closed++
652		}
653	
654		return closed, nil
655	}
