802	// returnWindowDays is the maximum number of days after order completion
803	// within which a return request may be filed.
804	const returnWindowDays = 14
805	
806	// WithinReturnWindow reports whether the given completedAt timestamp is
807	// within the 14-day return window. completedAt must be in RFC3339 format.
808	func WithinReturnWindow(completedAt string) bool {
809		t, err := time.Parse(time.RFC3339, completedAt)
810		if err != nil {
811			// Fallback: attempt SQLite datetime format.
812			t, err = time.Parse("2006-01-02 15:04:05", completedAt)
813			if err != nil {
814				return false
815			}
816		}
817		return time.Since(t) <= time.Duration(returnWindowDays)*24*time.Hour
818	}
