124	// backorder record is created for the shortfall.
125	// The order is advanced from pending_shipment → in_transit on the first issue.
126	func (s *DistributionService) markItemsFulfilled(orderID, actorID int64, items []IssueItem) error {
127		for _, item := range items {
128			issued := item.IssuedQty
129			if issued <= 0 {
130				issued = item.Qty
131			}
132	
133			if issued >= item.Qty {
134				// Fully satisfied — mark fulfilled.
135				if err := s.orderRepo.MarkOrderItemFulfilled(orderID, item.MaterialID); err != nil {
136					return fmt.Errorf("markItemsFulfilled: mark fulfilled material %d: %w", item.MaterialID, err)
137				}
138			} else {
139				// Partial issue — mark backordered and record the shortfall.
140				if err := s.orderRepo.MarkOrderItemBackordered(orderID, item.MaterialID); err != nil {
141					return fmt.Errorf("markItemsFulfilled: mark backordered material %d: %w", item.MaterialID, err)
142				}
143				itemID, err := s.orderRepo.GetOrderItemID(orderID, item.MaterialID)
144				if err != nil {
145					return fmt.Errorf("markItemsFulfilled: get order_item_id material %d: %w", item.MaterialID, err)
146				}
147				shortfall := item.Qty - issued
148				if _, err := s.orderRepo.CreateBackorder(itemID, shortfall); err != nil {
149					return fmt.Errorf("markItemsFulfilled: create backorder material %d: %w", item.MaterialID, err)
150				}
151				observability.Distribution.Warn("partial issue — backorder created",
152					"order_id", orderID, "material_id", item.MaterialID,
153					"issued", issued, "shortfall", shortfall)
154			}
155		}
156	
157		// Advance order from pending_shipment → in_transit on first issue.
158		order, err := s.orderRepo.GetByID(orderID)
159		if err != nil {
160			return err
161		}
162		if order.Status == "pending_shipment" {
163			if err := s.orderRepo.Transition(orderID, actorID, "in_transit", "items issued by clerk", s.materialRepo); err != nil {
164				return fmt.Errorf("markItemsFulfilled: advance to in_transit: %w", err)
165			}
166		}
167	
168		return nil
169	}
170	
171	// ---------------------------------------------------------------
172	// Return
173	// ---------------------------------------------------------------
174	
175	// RecordReturn records a "returned" distribution event and releases inventory
176	// (increments available_qty by qty).
177	func (s *DistributionService) RecordReturn(orderID, materialID, actorID int64, scanID string, qty int) error {
178		if qty <= 0 {
179			return errors.New("service: RecordReturn: qty must be positive")
180		}
181	
182		// Verify order exists.
183		if _, err := s.orderRepo.GetByID(orderID); err != nil {
184			if errors.Is(err, sql.ErrNoRows) {
185				return fmt.Errorf("service: RecordReturn: order %d not found", orderID)
186			}
187			return fmt.Errorf("service: RecordReturn: load order: %w", err)
188		}
189	
190		orderIDPtr := &orderID
191		actorIDPtr := &actorID
192		scanIDPtr := &scanID
193	
194		evt := &models.DistributionEvent{
195			OrderID:     orderIDPtr,
196			MaterialID:  materialID,
197			Qty:         qty,
198			EventType:   "returned",
199			ScanID:      scanIDPtr,
200			ActorID:     actorIDPtr,
201			CustodyFrom: stringPtr("student"),
202			CustodyTo:   stringPtr("clerk"),
203		}
204		if _, err := s.distRepo.RecordEvent(evt); err != nil {
205			return fmt.Errorf("service: RecordReturn: record event: %w", err)
206		}
207	
208		// Release inventory back to available stock.
209		if err := s.materialRepo.Release(materialID, qty); err != nil {
210			return fmt.Errorf("service: RecordReturn: release inventory: %w", err)
211		}
212	
213		observability.Distribution.Info("item returned", "order_id", orderID, "material_id", materialID, "qty", qty, "scan_id", scanID, "actor_id", actorID)
214		return nil
215	}
216	
217	// ---------------------------------------------------------------
218	// Exchange
219	// ---------------------------------------------------------------
220	
221	// RecordExchange swaps an old copy for a new one in a single logical operation:
222	//  1. Records a "returned" event for oldMaterialID.
223	//  2. Verifies the new material has available stock.
224	//  3. Records an "issued" event for newMaterialID and decrements its
225	//     available_qty.
226	func (s *DistributionService) RecordExchange(orderID, oldMaterialID, newMaterialID, actorID int64, scanID string, qty int) error {
227		if qty <= 0 {
228			return errors.New("service: RecordExchange: qty must be positive")
229		}
230	
231		// Return the old copy first (releases its inventory).
232		if err := s.RecordReturn(orderID, oldMaterialID, actorID, scanID, qty); err != nil {
233			return fmt.Errorf("service: RecordExchange: return old: %w", err)
234		}
235	
236		// Check new material stock.
237		newMat, err := s.materialRepo.GetByID(newMaterialID)
238		if err != nil {
239			if errors.Is(err, sql.ErrNoRows) {
240				return fmt.Errorf("service: RecordExchange: new material %d not found", newMaterialID)
241			}
242			return fmt.Errorf("service: RecordExchange: load new material: %w", err)
243		}
244		if newMat.AvailableQty < qty {
245			return fmt.Errorf("service: RecordExchange: insufficient stock for material %q (available %d, requested %d)",
246				newMat.Title, newMat.AvailableQty, qty)
247		}
248	
249		orderIDPtr := &orderID
250		actorIDPtr := &actorID
251		newScanID := scanID + "_exch"
252		scanIDPtr := &newScanID
253	
254		evt := &models.DistributionEvent{
255			OrderID:     orderIDPtr,
256			MaterialID:  newMaterialID,
257			Qty:         qty,
258			EventType:   "issued",
259			ScanID:      scanIDPtr,
260			ActorID:     actorIDPtr,
261			CustodyFrom: stringPtr("clerk"),
262			CustodyTo:   stringPtr("student"),
263		}
264		if _, err := s.distRepo.RecordEvent(evt); err != nil {
265			return fmt.Errorf("service: RecordExchange: record issue event: %w", err)
266		}
267	
268		// Reserve the newly issued material's inventory.
269		if err := s.materialRepo.Reserve(newMaterialID, qty); err != nil {
270			return fmt.Errorf("service: RecordExchange: reserve new material inventory: %w", err)
271		}
272	
273		observability.Distribution.Info("item exchanged", "order_id", orderID, "old_material_id", oldMaterialID, "new_material_id", newMaterialID, "qty", qty, "actor_id", actorID)
274		return nil
275	}
276	
277	
278	// ---------------------------------------------------------------
279	// Reissue
280	// ---------------------------------------------------------------
281	
282	// ReissueItem handles lost or damaged copy replacement:
283	//   - Records a "lost" or "damaged" event for oldScanID (marking it out of
284	//     circulation).
285	//   - Records a new "issued" event for newScanID.
286	//
287	// reason must be "lost" or "damaged".
288	func (s *DistributionService) ReissueItem(orderID, materialID, actorID int64, oldScanID, newScanID, reason string) error {
289		if reason != "lost" && reason != "damaged" {
290			return fmt.Errorf("service: ReissueItem: invalid reason %q (must be 'lost' or 'damaged')", reason)
291		}
292		if oldScanID == "" || newScanID == "" {
293			return errors.New("service: ReissueItem: both oldScanID and newScanID are required")
294		}
295	
296		// Verify order exists.
297		if _, err := s.orderRepo.GetByID(orderID); err != nil {
298			if errors.Is(err, sql.ErrNoRows) {
299				return fmt.Errorf("service: ReissueItem: order %d not found", orderID)
300			}
301			return fmt.Errorf("service: ReissueItem: load order: %w", err)
302		}
303	
304		orderIDPtr := &orderID
305		actorIDPtr := &actorID
306	
307		// Record the loss/damage event for the old scan ID.
308		oldEvt := &models.DistributionEvent{
309			OrderID:    orderIDPtr,
310			MaterialID: materialID,
311			Qty:        1,
312			EventType:  reason, // "lost" or "damaged"
313			ScanID:     &oldScanID,
314			ActorID:    actorIDPtr,
315		}
316		if _, err := s.distRepo.RecordEvent(oldEvt); err != nil {
317			return fmt.Errorf("service: ReissueItem: record %s event: %w", reason, err)
318		}
319	
320		// Issue the replacement copy.
321		newEvt := &models.DistributionEvent{
322			OrderID:     orderIDPtr,
323			MaterialID:  materialID,
324			Qty:         1,
325			EventType:   "issued",
326			ScanID:      &newScanID,
327			ActorID:     actorIDPtr,
328			CustodyFrom: stringPtr("clerk"),
329			CustodyTo:   stringPtr("student"),
330		}
331		if _, err := s.distRepo.RecordEvent(newEvt); err != nil {
332			return fmt.Errorf("service: ReissueItem: record replacement issue event: %w", err)
333		}
334	
335		observability.Distribution.Info("item reissued", "old_scan_id", oldScanID, "new_scan_id", newScanID, "reason", reason)
336		return nil
337	}
338	
339	// ---------------------------------------------------------------
340	// Ledger / chain queries — thin pass-through
341	// ---------------------------------------------------------------
342	
343	// GetLedger returns a paginated, filtered view of distribution events.
344	func (s *DistributionService) GetLedger(filters repository.DistributionFilter, limit, offset int) ([]models.DistributionEvent, error) {
345		return s.distRepo.ListEvents(filters, limit, offset)
346	}
347	
348	// GetCustodyChain returns the full event history for a physical copy.
349	func (s *DistributionService) GetCustodyChain(scanID string) ([]models.DistributionEvent, error) {
350		if scanID == "" {
351			return nil, errors.New("service: GetCustodyChain: scanID is required")
352		}
353		return s.distRepo.GetCustodyChain(scanID)
354	}
355	
356	// GetPendingIssues returns the clerk's pick list.
357	func (s *DistributionService) GetPendingIssues(limit, offset int) ([]repository.PendingIssue, error) {
358		return s.distRepo.GetPendingIssues(limit, offset)
359	}
360	
361	// CountBackorders returns the total number of unresolved backorder records.
362	func (s *DistributionService) CountBackorders() (int, error) {
363		return s.distRepo.CountBackorders()
364	}
365	
366	// ---------------------------------------------------------------
367	// helpers
368	// ---------------------------------------------------------------
369	
370	func stringPtr(s string) *string { return &s }
