	if err := db.QueryRow(`SELECT status FROM return_requests WHERE id = ?`, rrID).Scan(&status); err != nil {
		t.Fatalf("query return_request status: %v", err)
	}
	if status != "approved" {
		t.Errorf("expected status 'approved', got %q", status)
	}
}"}

