11	// CourseService orchestrates course creation, section management, and material
12	// demand planning for instructor users.
13	type CourseService struct {
14		courseRepo   *repository.CourseRepository
15		materialRepo *repository.MaterialRepository
16	}
17	
18	// NewCourseService wires the service to its repositories.
19	func NewCourseService(cr *repository.CourseRepository, mr *repository.MaterialRepository) *CourseService {
20		return &CourseService{courseRepo: cr, materialRepo: mr}
21	}
22	
23	// CreateCourse registers a new course owned by the given instructor.
24	func (s *CourseService) CreateCourse(instructorID int64, name, subject, gradeLevel, academicYear string) (*models.Course, error) {
25		if name == "" {
26			return nil, errors.New("service: CreateCourse: course name is required")
27		}
28		c, err := s.courseRepo.CreateCourse(instructorID, name, subject, gradeLevel, academicYear)
29		if err != nil {
30			return nil, fmt.Errorf("service: CreateCourse: %w", err)
31		}
32		return c, nil
33	}
34	
35	// ListCourses returns all courses owned by the instructor.
36	func (s *CourseService) ListCourses(instructorID int64) ([]models.Course, error) {
37		return s.courseRepo.GetCoursesByInstructor(instructorID)
38	}
39	
40	// GetCourse returns a single course; returns an error if it does not belong to
41	// the requesting instructor (unless the caller is an admin).
42	func (s *CourseService) GetCourse(courseID, callerID int64, isAdmin bool) (*models.Course, error) {
43		c, err := s.courseRepo.GetCourseByID(courseID)
44		if err != nil {
45			return nil, fmt.Errorf("service: GetCourse: %w", err)
46		}
47		if !isAdmin && c.InstructorID != callerID {
48			return nil, errors.New("service: GetCourse: not authorized")
49		}
50		return c, nil
51	}
52	
53	// AddSection appends a section to the given course.
54	func (s *CourseService) AddSection(courseID int64, name, period, room string) (*models.CourseSection, error) {
55		if name == "" {
56			return nil, errors.New("service: AddSection: section name is required")
57		}
58		return s.courseRepo.AddSection(courseID, name, period, room)
59	}
60	
61	// GetSections returns all sections for a course.
62	func (s *CourseService) GetSections(courseID int64) ([]models.CourseSection, error) {
63		return s.courseRepo.GetSectionsByCourse(courseID)
64	}
65	
66	// AddPlanItem adds (or updates) a material demand line for a course.
67	// Verifies the material exists and is active before recording the plan.
68	func (s *CourseService) AddPlanItem(courseID, materialID int64, requestedQty int, notes string) (*models.CoursePlan, error) {
69		if requestedQty <= 0 {
70			return nil, errors.New("service: AddPlanItem: requested_qty must be positive")
71		}
72		mat, err := s.materialRepo.GetByID(materialID)
73		if err != nil {
74			return nil, fmt.Errorf("service: AddPlanItem: material %d not found", materialID)
75		}
76		if mat.Status != "active" {
77			return nil, fmt.Errorf("service: AddPlanItem: material %q is not active", mat.Title)
78		}
79		return s.courseRepo.UpsertPlanItem(courseID, materialID, requestedQty, notes)
80	}
81	
82	// ApprovePlanItem approves a plan item (admin/instructor workflow).
83	func (s *CourseService) ApprovePlanItem(planID int64, approvedQty int) error {
84		if approvedQty < 0 {
85			return errors.New("service: ApprovePlanItem: approved_qty cannot be negative")
86		}
87		return s.courseRepo.ApprovePlanItem(planID, approvedQty)
88	}
