//go:build ignore

package main

import (
	"database/sql"
	"fmt"
	"log"
	"os"

	_ "github.com/mattn/go-sqlite3"
	"w2t86/internal/db"
)

func main() {
	// Create a temp DB with pre-existing users rows (simulates a non-empty prod DB)
	tmpDB := "/tmp/migration_test.db"
	os.Remove(tmpDB)

	conn, err := sql.Open("sqlite3", tmpDB+"?_foreign_keys=on")
	if err != nil {
		log.Fatal(err)
	}

	// Bootstrap minimal schema + insert rows BEFORE the migration runs
	bootstrap := `
		CREATE TABLE IF NOT EXISTS _migrations (filename TEXT PRIMARY KEY, applied_at TEXT DEFAULT (datetime('now')));
		CREATE TABLE IF NOT EXISTS users (
			id            INTEGER PRIMARY KEY,
			username      TEXT UNIQUE NOT NULL,
			email         TEXT NOT NULL,
			password_hash TEXT NOT NULL,
			role          TEXT NOT NULL DEFAULT 'student'
		);
		INSERT INTO users (username, email, password_hash) VALUES
			('alice', 'alice@x.com', 'hash1'),
			('bob',   'bob@x.com',   'hash2'),
			('carol', 'carol@x.com', 'hash3');
		-- Mark 001-004 as already applied so only 005 runs
		INSERT INTO _migrations (filename) VALUES
			('001_schema.sql'),
			('002_add_date_of_birth.sql'),
			('003_financial_transactions.sql'),
			('004_add_full_name.sql');
	`
	if _, err := conn.Exec(bootstrap); err != nil {
		log.Fatalf("bootstrap: %v", err)
	}
	conn.Close()

	// Now open via the real db.Open (runs migration runner)
	conn2, err := db.Open(tmpDB)
	if err != nil {
		log.Fatalf("db.Open (migration): %v", err)
	}
	defer conn2.Close()

	// Verify the column exists and uniqueness is enforced
	if _, err := conn2.Exec(`UPDATE users SET external_id = 'EID-001' WHERE username = 'alice'`); err != nil {
		log.Fatalf("set alice external_id: %v", err)
	}
	// Duplicate should be rejected
	_, err = conn2.Exec(`UPDATE users SET external_id = 'EID-001' WHERE username = 'bob'`)
	if err == nil {
		log.Fatal("FAIL: duplicate external_id was accepted; UNIQUE not enforced")
	}
	fmt.Println("duplicate correctly rejected:", err)

	// NULL values must be allowed for multiple rows
	if _, err := conn2.Exec(`UPDATE users SET external_id = NULL WHERE username IN ('bob','carol')`); err != nil {
		log.Fatalf("null external_id: %v", err)
	}
	fmt.Println("PASS: migration applied, UNIQUE enforced, multiple NULLs allowed")
	os.Remove(tmpDB)
}
EOF
go run /tmp/test_migration.go", "description": "Run a live simulation of the migration against a pre-populated users table", "timeout": 30000}

