func TestMigration005_NonEmptyTable(t *testing.T) {
	tmpDB := t.TempDir() + "/test.db"

	// Open a raw connection and seed schema + rows BEFORE the migration runner sees it
	conn, err := sql.Open("sqlite3", tmpDB+"?_foreign_keys=on")
	if err != nil {
		t.Fatal(err)
	}
	_, err = conn.Exec(`
		CREATE TABLE _migrations (filename TEXT PRIMARY KEY, applied_at TEXT DEFAULT (datetime('now')));
		CREATE TABLE users (
			id            INTEGER PRIMARY KEY,
			username      TEXT UNIQUE NOT NULL,
			email         TEXT NOT NULL,
			password_hash TEXT NOT NULL,
			role          TEXT NOT NULL DEFAULT 'student'
		);
		INSERT INTO users (username, email, password_hash) VALUES
			('alice', 'a@x.com', 'h1'),
			('bob',   'b@x.com', 'h2'),
			('carol', 'c@x.com', 'h3');
		INSERT INTO _migrations (filename) VALUES
			('001_schema.sql'),
			('002_add_date_of_birth.sql'),
			('003_financial_transactions.sql'),
			('004_add_full_name.sql');
	`)
	if err != nil {
		t.Fatalf("seed: %v", err)
	}
	conn.Close()

	// db.Open runs RunMigrations — only 005+ will execute
	wd, _ := os.Getwd()
	_ = wd
	conn2, err := db.Open(tmpDB)
	if err != nil {
		t.Fatalf("db.Open: %v", err)
	}
	defer conn2.Close()

	// column must exist and accept a value
	if _, err := conn2.Exec(`UPDATE users SET external_id = 'EID-001' WHERE username = 'alice'`); err != nil {
		t.Fatalf("set external_id: %v", err)
	}
	// duplicate must be rejected
	if _, err := conn2.Exec(`UPDATE users SET external_id = 'EID-001' WHERE username = 'bob'`); err == nil {
		t.Fatal("expected UNIQUE violation; got nil")
	}
	// multiple NULLs must be allowed
	if _, err := conn2.Exec(`UPDATE users SET external_id = NULL WHERE username IN ('bob','carol')`); err != nil {
		t.Fatalf("NULL external_id: %v", err)
	}
	t.Log("PASS: column added, UNIQUE enforced, multiple NULLs allowed")
}
EOF
