package db_test

import (
	"database/sql"
	"os"
	"path/filepath"
	"runtime"
	"testing"

	_ "github.com/mattn/go-sqlite3"
	"w2t86/internal/db"
)

// TestMigration005_NonEmptyTable verifies that 005_add_external_id.sql applies
// safely to a users table that already contains rows — the scenario that caused
// the "Cannot add a UNIQUE column" error with the original single-statement form.
func TestMigration005_NonEmptyTable(t *testing.T) {
	// Resolve repo root so RunMigrations can find ./migrations
	_, thisFile, _, _ := runtime.Caller(0)
	repoRoot := filepath.Join(filepath.Dir(thisFile), "..", "..")
	origDir, _ := os.Getwd()
	if err := os.Chdir(repoRoot); err != nil {
		t.Fatalf("chdir repo root: %v", err)
	}
	t.Cleanup(func() { os.Chdir(origDir) })

	tmpDB := t.TempDir() + "/test.db"

	// Seed a minimal schema with existing rows and mark migrations 001–004 as
	// already applied, so only 005+ will be executed by db.Open.
	conn, err := sql.Open("sqlite3", tmpDB+"?_foreign_keys=on")
	if err != nil {
		t.Fatal(err)
	}
	_, err = conn.Exec(`
		CREATE TABLE _migrations (
			filename   TEXT PRIMARY KEY,
			applied_at TEXT DEFAULT (datetime('now'))
		);
		CREATE TABLE users (
			id            INTEGER PRIMARY KEY,
			username      TEXT UNIQUE NOT NULL,
			email         TEXT NOT NULL,
			password_hash TEXT NOT NULL,
			role          TEXT NOT NULL DEFAULT 'student'
		);
		INSERT INTO users (username, email, password_hash) VALUES
			('alice', 'a@x.com', 'h1'),
			('bob',   'b@x.com', 'h2'),
			('carol', 'c@x.com', 'h3');
		INSERT INTO _migrations (filename) VALUES
			('001_schema.sql'),
			('002_add_date_of_birth.sql'),
			('003_financial_transactions.sql'),
			('004_add_full_name.sql');
	`)
	if err != nil {
		t.Fatalf("seed: %v", err)
	}
	conn.Close()

	// db.Open runs RunMigrations; only 005+ will execute.
	conn2, err := db.Open(tmpDB)
	if err != nil {
		t.Fatalf("db.Open (migration 005): %v", err)
	}
	defer conn2.Close()

	// Column must exist and accept a value.
	if _, err := conn2.Exec(`UPDATE users SET external_id = 'EID-001' WHERE username = 'alice'`); err != nil {
		t.Fatalf("set external_id: %v", err)
	}

	// Duplicate non-NULL value must be rejected.
	if _, err := conn2.Exec(`UPDATE users SET external_id = 'EID-001' WHERE username = 'bob'`); err == nil {
		t.Fatal("expected UNIQUE violation for duplicate external_id; got nil")
