	// Multiple NULLs must be allowed (NULL != NULL for UNIQUE purposes).
	if _, err := conn2.Exec(`UPDATE users SET external_id = NULL WHERE username IN ('bob', 'carol')`); err != nil {
		t.Fatalf("NULL external_id rejected: %v", err)
