1	package db
2	
3	import (
4		"database/sql"
5		"fmt"
6		"os"
7		"path/filepath"
8		"sort"
9		"strings"
10	
11		_ "github.com/mattn/go-sqlite3"
12	)
13	
14	const driverDSN = "%s?_journal_mode=WAL&_foreign_keys=on&_busy_timeout=5000"
15	
16	// Open opens (or creates) the SQLite database at dbPath, configures WAL mode,
17	// foreign-key enforcement, and a busy timeout, then runs all pending
18	// migrations.  It returns the ready-to-use *sql.DB or an error.
19	func Open(dbPath string) (*sql.DB, error) {
20		// Ensure the parent directory exists so SQLite can create the file.
21		if dir := filepath.Dir(dbPath); dir != "" && dir != "." {
22			if err := os.MkdirAll(dir, 0o755); err != nil {
23				return nil, fmt.Errorf("db: create directory %q: %w", dir, err)
24			}
25		}
26	
27		dsn := fmt.Sprintf(driverDSN, dbPath)
28		db, err := sql.Open("sqlite3", dsn)
29		if err != nil {
30			return nil, fmt.Errorf("db: open %q: %w", dbPath, err)
31		}
32	
33		// Verify connectivity.
34		if err := db.Ping(); err != nil {
35			db.Close()
36			return nil, fmt.Errorf("db: ping %q: %w", dbPath, err)
37		}
38	
39		// SQLite performs best with a single writer connection.
40		db.SetMaxOpenConns(1)
41	
42		if err := RunMigrations(db); err != nil {
43			db.Close()
44			return nil, err
45		}
46	
47		return db, nil
48	}
49	
50	// RunMigrations discovers every *.sql file inside the "migrations/" directory
51	// (relative to the working directory), sorts them lexicographically so that
52	// numbered files like 001_schema.sql are applied in order, and executes each
53	// one inside its own transaction.  Files that have already been applied are
54	// tracked in the _migrations table to make the operation idempotent.
55	func RunMigrations(db *sql.DB) error {
56		// Bootstrap the tracking table.
57		const bootstrap = `
58	CREATE TABLE IF NOT EXISTS _migrations (
59	    filename TEXT PRIMARY KEY,
60	    applied_at TEXT DEFAULT (datetime('now'))
61	);`
62		if _, err := db.Exec(bootstrap); err != nil {
63			return fmt.Errorf("db: bootstrap migrations table: %w", err)
64		}
65	
66		entries, err := os.ReadDir("migrations")
67		if err != nil {
68			if os.IsNotExist(err) {
69				// No migrations directory is not an error during testing.
70				return nil
71			}
72			return fmt.Errorf("db: read migrations dir: %w", err)
73		}
74	
75		// Collect .sql files and sort them.
76		var files []string
77		for _, e := range entries {
78			if !e.IsDir() && strings.HasSuffix(e.Name(), ".sql") {
79				files = append(files, e.Name())
80			}
81		}
82		sort.Strings(files)
83	
84		for _, name := range files {
85			applied, err := isMigrationApplied(db, name)
86			if err != nil {
87				return err
88			}
89			if applied {
90				continue
91			}
92	
93			content, err := os.ReadFile(filepath.Join("migrations", name))
94			if err != nil {
95				return fmt.Errorf("db: read migration %q: %w", name, err)
96			}
97	
98			if err := applyMigration(db, name, string(content)); err != nil {
99				return err
100			}
101		}
102	
103		return nil
104	}
105	
106	func isMigrationApplied(db *sql.DB, filename string) (bool, error) {
107		var count int
108		err := db.QueryRow(
109			`SELECT COUNT(*) FROM _migrations WHERE filename = ?`, filename,
110		).Scan(&count)
111		if err != nil {
112			return false, fmt.Errorf("db: check migration %q: %w", filename, err)
113		}
114		return count > 0, nil
115	}
116	
117	func applyMigration(db *sql.DB, filename, sql string) error {
118		tx, err := db.Begin()
119		if err != nil {
120			return fmt.Errorf("db: begin tx for migration %q: %w", filename, err)
121		}
122		defer tx.Rollback() //nolint:errcheck
123	
124		if _, err := tx.Exec(sql); err != nil {
125			return fmt.Errorf("db: execute migration %q: %w", filename, err)
126		}
127	
128		if _, err := tx.Exec(
129			`INSERT INTO _migrations(filename) VALUES(?)`, filename,
130		); err != nil {
131			return fmt.Errorf("db: record migration %q: %w", filename, err)
132		}
133	
134		if err := tx.Commit(); err != nil {
135			return fmt.Errorf("db: commit migration %q: %w", filename, err)
136		}
137	
138		return nil
139	}
